import { Request, Response, NextFunction } from 'express';
import { toCamelCase } from '../utils/caseUtils.js';

type JsonValue = string | number | boolean | null | undefined | { [key: string]: JsonValue } | JsonValue[];

export const namingMiddleware = (req: Request, _res: Response, next: NextFunction) => {
  if (req.body && typeof req.body === 'object') {
    // Cast to JsonValue for toCamelCase then back to req.body's type
    const camelBody = toCamelCase(req.body as JsonValue);
    req.body = camelBody as typeof req.body;
  }
  
  if (req.query && typeof req.query === 'object') {
    // Cast to JsonValue for toCamelCase then back to req.query's type
    const camelQuery = toCamelCase(req.query as unknown as JsonValue);
    req.query = camelQuery as typeof req.query;
  }

  next();
};

import multer, { StorageEngine, FileFilterCallback, Multer } from 'multer';
import path from 'path';
import fs from 'fs';
import { fileURLToPath } from 'url';
import type { Request } from 'express';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Base upload directory
const baseUploadDir = path.join(__dirname, '../uploads');

// Ensure base directory exists
if (!fs.existsSync(baseUploadDir)) {
  fs.mkdirSync(baseUploadDir, { recursive: true });
}

// Allowed file types and extensions
const ALLOWED_MIME_TYPES: string[] = [
  'image/jpeg',
  'image/png',
  'image/webp',
  'application/pdf',
  'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  'application/vnd.ms-excel',
  'application/msword',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
];

const ALLOWED_EXTENSIONS: string[] = ['.jpg', '.jpeg', '.png', '.webp', '.pdf', '.xlsx', '.xls', '.doc', '.docx'];

const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB

/**
 * Factory function to create an uploader for a specific subfolder
 * @param subfolder - Name of the subfolder within uploads directory
 */
const createUploader = (subfolder: string): Multer => {
  const targetDir = path.join(baseUploadDir, subfolder);

  // Ensure subfolder exists
  if (!fs.existsSync(targetDir)) {
    fs.mkdirSync(targetDir, { recursive: true });
  }

  const storage: StorageEngine = multer.diskStorage({
    destination: (_req: Request, _file: Express.Multer.File, cb: (error: Error | null, destination: string) => void): void => {
      cb(null, targetDir);
    },
    filename: (_req: Request, file: Express.Multer.File, cb: (error: Error | null, filename: string) => void): void => {
      const uniqueSuffix = `${Date.now()}-${Math.round(Math.random() * 1e9)}`;
      // Sanitize original name
      const sanitizedName = file.originalname.replace(/\s+/g, '_');
      cb(null, `${subfolder}-${uniqueSuffix}${path.extname(sanitizedName)}`);
    }
  });

  const fileFilter = (
    _req: Request,
    file: Express.Multer.File,
    cb: FileFilterCallback
  ): void => {
    const ext = path.extname(file.originalname).toLowerCase();

    if (ALLOWED_MIME_TYPES.includes(file.mimetype) && ALLOWED_EXTENSIONS.includes(ext)) {
      cb(null, true);
    } else {
      cb(new Error('Invalid file type or extension. Only Images, PDFs, Word documents, and Excel files are allowed.'));
    }
  };

  return multer({
    storage,
    fileFilter,
    limits: { fileSize: MAX_FILE_SIZE }
  });
};

