import { db } from '../db/index.js';
import { dailyTimeRecords, policyViolations, employeeMemos } from '../db/schema.js';
import { and, eq, gte, lte, inArray } from 'drizzle-orm';

interface AttendanceScoreResult {
  score: number; // 1-5
  details: {
    totalLates: number;
    totalUndertime: number;
    totalAbsences: number;
    totalLateMinutes: number;
    ratingDescription: string;
  };
}

export const calculateAttendanceScore = async (
  employeeId: string | number,
  startDate: string,
  endDate: string
): Promise<AttendanceScoreResult> => {
  const empIdStr = String(employeeId);

  // Parse strings to full date boundaries if needed, but since date column is date YYYY-MM-DD
  // and created_at is timestamp, we use string comparisons compatible with MySQL
  const dtrRecords = await db.select()
  .from(dailyTimeRecords)
  .where(and(
      eq(dailyTimeRecords.employeeId, empIdStr),
      gte(dailyTimeRecords.date, startDate),
      lte(dailyTimeRecords.date, endDate)
  ));

  // Fetch Policy Violations within the period
  const violations = await db.select({
      id: policyViolations.id
  })
  .from(policyViolations)
  .where(and(
      eq(policyViolations.employeeId, empIdStr),
      inArray(policyViolations.type, ['habitual_tardiness', 'habitual_undertime', 'absence']),
      gte(policyViolations.createdAt, `${startDate} 00:00:00`),
      lte(policyViolations.createdAt, `${endDate} 23:59:59`)
  ));

  const violationCount = violations.length;

  // Fetch issued Memos within the period to enforce strict Performance Ceilings
  const memos = await db.select({
      severity: employeeMemos.severity
  })
  .from(employeeMemos)
  .where(and(
      eq(employeeMemos.employeeId, Number(employeeId)),
      gte(employeeMemos.createdAt, `${startDate} 00:00:00`),
      lte(employeeMemos.createdAt, `${endDate} 23:59:59`)
  ));

  let hasMajor = false;
  let hasModerate = false;
  let hasMinor = false;
  let _memoCount = 0;

  memos.forEach(memo => {
      if (memo.severity === 'major') hasMajor = true;
      if (memo.severity === 'moderate') hasModerate = true;
      if (memo.severity === 'minor') hasMinor = true;
      memoCount++;
  });

  let totalLates = 0;
  let totalUndertime = 0;
  let totalAbsences = 0;
  let totalLateMinutes = 0;

  dtrRecords.forEach(record => {
      const isStatusLate = record.status === 'Late' || record.status === 'Late/Undertime';
      const isStatusUndertime = record.status === 'Undertime' || record.status === 'Late/Undertime';
      const lateMins = record.lateMinutes || 0;
      const underMins = record.undertimeMinutes || 0;

      if (isStatusLate || lateMins > 0) {
          totalLates++;
          totalLateMinutes += lateMins;
      }
      
      if (isStatusUndertime || underMins > 0) {
          totalUndertime++;
      }
      
      if (record.status === 'Absent' || record.status === 'AWOL' || record.status === 'No Logs') {
          totalAbsences++;
      }
  });

  const totalInstances = totalLates + totalUndertime;

  let score = 5;
  let ratingDescription = 'Outstanding';

  // Strict Scoring Logic (Reference: CSC / Internal Policy)
  // 5 - Outstanding: No lates, no undertime, no absences.
  // 4 - Very Satisfactory: <= 5 instances AND <= 60 mins late AND 0 Absences
  // 3 - Satisfactory: <= 10 instances AND <= 120 mins late AND <= 1 Absence
  // 2 - Unsatisfactory: <= 15 instances AND <= 2 Absences
  // 1 - Poor: Habitual (>= 3 absences OR >= 10 consecutive absences checks) OR Violation

  // Apply base score calculations
  if (totalInstances === 0 && totalAbsences === 0 && totalLateMinutes === 0) {
      score = 5;
      ratingDescription = 'Outstanding';
  } else if (totalInstances <= 5 && totalLateMinutes <= 60 && totalAbsences === 0) {
      score = 4;
      ratingDescription = 'Very Satisfactory';
  } else if (totalInstances <= 10 && totalLateMinutes <= 120 && totalAbsences <= 1) {
      score = 3;
      ratingDescription = 'Satisfactory';
  } else if (totalInstances <= 15 && totalAbsences <= 2) { 
      score = 2;
      ratingDescription = 'Unsatisfactory';
  } else {
      score = 1;
      ratingDescription = 'Poor';
  }

  // ENFORCE CEILING CAPS BASED ON MEMO SEVERITY
  // These override the base score if a memo penalty was formally issued.
  if (hasMajor) {
      score = 1;
      ratingDescription = `Poor (Formally Reprimanded - Major Offense)`;
  } else if (hasModerate && score > 2) {
      score = 2; // Ceiling of 2 for moderate offenses
      ratingDescription = `Unsatisfactory (Formally Reprimanded - Moderate Offense)`;
  } else if (hasMinor && score > 3) {
      score = 3; // Ceiling of 3 for minor offenses
      ratingDescription = `Satisfactory (Formally Reprimanded - Minor Offense)`;
  } 
  
  // Failsafes for extreme violations that bypassed memos or were ignored
  else if (violationCount > 0 && score > 1) {
      score = 1;
      ratingDescription = `Poor (Has ${violationCount} Unresolved Policy Violation/s)`;
  } else if (totalAbsences >= 3 && score > 1) {
      score = 1;
      ratingDescription = `Poor (Habitual Absenteeism: ${totalAbsences} days)`;
  } else if (totalLateMinutes > 240 && score > 1) { // > 4 hours total
      score = 1;
      ratingDescription = `Poor (Severe Tardiness: ${totalLateMinutes} mins)`;
  }

  return {
    score,
    details: {
      totalLates,
      totalUndertime,
      totalAbsences,
      totalLateMinutes,
      ratingDescription
    }
  };
};

import Imap from 'imap';
import { simpleParser, ParsedMail, AddressObject, Attachment } from 'mailparser';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { db } from '../db/index.js';
import { recruitmentJobs, recruitmentApplicants } from '../db/schema.js';
import { eq } from 'drizzle-orm';
import { getTemplateForStage, replaceVariables, sendEmailNotification } from '../utils/emailHelpers.js';
import { notifyAdmins } from '../controllers/notificationController.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

interface EmailCheckResult {
  success: boolean;
  message: string;
  processed: number;
}

interface ApplicantData {
  jobId: number | null;
  firstName: string;
  lastName: string;
  email: string;
  resumePath: string | null;
  emailSubject: string;
}

/**
 * Parsed name structure
 */
interface ParsedName {
  firstName: string;
  lastName: string;
}

/**
 * IMAP configuration type
 */
interface ImapConfig {
  user: string | undefined;
  password: string | undefined;
  host: string;
  port: number;
  tls: boolean;
  tlsOptions: { rejectUnauthorized: boolean };
}

// Ignored senders (bots, no-reply, notifications)
const IGNORED_SENDERS = [
  'mailer-daemon', 'no-reply', 'noreply', 'postmaster',
  'security', 'accounts.google.com', 'facebookmail.com',
  'discordapp.com', 'discord.com', 'linkedin.com',
  'notifications', 'alert', 'support'
];

// Junk subject patterns
const JUNK_SUBJECTS = [
  'delivery status', 'failure', 'security alert',
  'verify your email', 'password', 'login', 'sign in',
  'undelivered', 'returned mail', 'confirmation'
];

/**
 * Get IMAP configuration from environment
 */
const getImapConfig = (): ImapConfig => ({
  user: process.env.EMAIL_USER,
  password: process.env.EMAIL_PASS,
  host: process.env.EMAIL_IMAP_HOST || 'imap.gmail.com',
  port: parseInt(process.env.EMAIL_IMAP_PORT || '993', 10),
  tls: true,
  tlsOptions: { rejectUnauthorized: false }
});

/**
 * Extract applicant name from email "From" field
 */
const extractNameFromEmail = (from: AddressObject | undefined): ParsedName => {
  try {
    if (from && from.value && from.value[0]) {
      const sender = from.value[0];
      if (sender.name) {
        const parts = sender.name.split(' ');
        return {
          firstName: parts[0] || 'Unknown',
          lastName: parts.slice(1).join(' ') || 'Applicant'
        };
      }
      // Fallback: use email prefix
      const emailPrefix = (sender.address || 'unknown').split('@')[0];
      return { firstName: emailPrefix, lastName: 'Applicant' };
    }
  } catch (err) {
    console.error('Error extracting name:', err);
  }
  return { firstName: 'Unknown', lastName: 'Applicant' };
};

/**
 * Extract sender email address from "From" field
 */
const extractEmailAddress = (from: AddressObject | undefined): string => {
  try {
    if (from && from.value && from.value[0]) {
      return from.value[0].address || 'unknown@email.com';
    }
  } catch (err) {
    console.error('Error extracting email:', err);
  }
  return 'unknown@email.com';
};

/**
 * Match email subject to a job posting
 */
const matchJobFromSubject = async (subject: string | undefined): Promise<number | null> => {
  try {
    if (!subject) return null;

    // Get all open jobs
    const jobs = await db.select({
      id: recruitmentJobs.id,
      title: recruitmentJobs.title
    })
    .from(recruitmentJobs)
    .where(eq(recruitmentJobs.status, 'Open'));

    // Try to find a matching job title in the subject
    const subjectLower = subject.toLowerCase();

    for (const job of jobs) {
      if (subjectLower.includes(job.title.toLowerCase())) {
        console.warn(`Matched job: ${job.title} (ID: ${job.id})`);
        return job.id;
      }
    }

    // No match found
    console.warn('No job match found for subject:', subject);
    return null;
  } catch (err) {
    console.error('Error matching job:', err);
    return null;
  }
};

/**
 * Save attachment to uploads folder
 */
const saveAttachment = async (attachment: Attachment): Promise<string | null> => {
  try {
    const uploadsDir = path.join(__dirname, '../uploads/resumes');

    // Create directory if it doesn't exist
    if (!fs.existsSync(uploadsDir)) {
      fs.mkdirSync(uploadsDir, { recursive: true });
    }

    // Generate unique filename with strict sanitization
    const timestamp = Date.now();
    const filename = attachment.filename || 'resume';
    // 100% Security: Strip all directory traversal attempts and only allow safe chars
    const safeFilename = path.basename(filename).replace(/[^a-zA-Z0-9.-]/g, '_');
    const uniqueFilename = `${timestamp}_${safeFilename}`;
    const filepath = path.join(uploadsDir, uniqueFilename);

    // Save file
    fs.writeFileSync(filepath, attachment.content);
    console.warn('Saved attachment:', uniqueFilename);

    return uniqueFilename;
  } catch (err) {
    console.error('Error saving attachment:', err);
    return null;
  }
};

/**
 * Save application to database
 */
const saveApplication = async (applicantData: ApplicantData): Promise<boolean> => {
  try {
    const { jobId, firstName, lastName, email, resumePath, emailSubject } = applicantData;

    await db.insert(recruitmentApplicants).values({
      jobId: jobId,
      firstName: firstName,
      lastName: lastName,
      email,
      resumePath: resumePath,
      source: 'email',
      emailSubject: emailSubject,
      emailReceivedAt: new Date().toISOString().slice(0, 19).replace('T', ' ')
    });

    console.warn(`Saved application from ${email} for job ${jobId || 'General'}`);

    let jobTitle = 'General Application';

    if (jobId) {
      const job = await db.query.recruitmentJobs.findFirst({
        where: eq(recruitmentJobs.id, Number(jobId)),
        columns: { title: true }
      });
      if (job) jobTitle = job.title;
    }

    // Send "Applied" email notification
    try {
      const template = await getTemplateForStage(db, 'Applied');
      if (template) {
        const variables = {
          applicantFirstName: firstName,
          applicantLastName: lastName,
          jobTitle: jobTitle,
          interviewDate: '',
          interviewLink: '',
          interviewPlatform: ''
        };

        const subject = replaceVariables(template.subjectTemplate, variables);
        const body = replaceVariables(template.bodyTemplate, variables);
        await sendEmailNotification(email, subject, body);
      }
    } catch (emailError) {
      console.error('Failed to send application email:', emailError);
    }

    // Notify admins about the new application via email
    try {
      await notifyAdmins({
        title: 'New Application (Email)',
        message: `${firstName} ${lastName} has applied via email for ${jobTitle}.`,
        type: 'recruitment',
        referenceId: jobId ? Number(jobId) : null
      });
    } catch (notifError) {
      console.error('Failed to send admin notification for email application:', notifError);
    }

    return true;
  } catch (err) {
    console.error('Error saving application:', err);
    return false;
  }
};

/**
 * Process a single email message
 */
const processEmail = async (parsed: ParsedMail): Promise<boolean> => {
  try {
    const subject = parsed.subject || 'No Subject';
    const senderEmail = extractEmailAddress(parsed.from);
    const { firstName, lastName } = extractNameFromEmail(parsed.from);

    console.warn(`Processing email from: ${senderEmail}, Subject: ${subject}`);

    // Junk email filter - check sender
    const senderLower = senderEmail.toLowerCase();
    if (IGNORED_SENDERS.some((ignored) => senderLower.includes(ignored))) {
      console.warn(`Skipping automated email from: ${senderEmail}`);
      return false;
    }

    // Check if subject indicates junk/notification
    const subjectLower = subject.toLowerCase();
    if (JUNK_SUBJECTS.some((junk) => subjectLower.includes(junk))) {
      console.warn(`Skipping notification email: ${subject}`);
      return false;
    }

    // Check if already processed (SKIPPED to allow testing)
    // if (await isEmailProcessed(senderEmail, subject)) {
    //   console.log('Email already processed, skipping...');
    //   return false;
    // }

    // Match to job
    const jobId = await matchJobFromSubject(subject);

    // Save attachments (resume)
    let resumePath: string | null = null;
    if (parsed.attachments && parsed.attachments.length > 0) {
      // Find PDF or DOC attachment (resume)
      const resumeAttachment = parsed.attachments.find(
        (att) =>
          att.filename &&
          (att.filename.toLowerCase().endsWith('.pdf') ||
            att.filename.toLowerCase().endsWith('.doc') ||
            att.filename.toLowerCase().endsWith('.docx'))
      );

      if (resumeAttachment) {
        resumePath = await saveAttachment(resumeAttachment);
      }
    }

    // Skip emails without resume attachment
    if (!resumePath) {
      console.warn(`Skipping email without resume attachment: ${subject}`);
      return false;
    }

    // Save to database
    const saved = await saveApplication({
      jobId,
      firstName,
      lastName,
      email: senderEmail,
      resumePath,
      emailSubject: subject
    });

    return saved;
  } catch (err) {
    console.error('Error processing email:', err);
    return false;
  }
};

/**
 * Fetch and process new emails from IMAP
 */
export const checkForNewApplications = (): Promise<EmailCheckResult> => {
  return new Promise((resolve, reject) => {
    const config = getImapConfig();

    if (!config.user || !config.password) {
      console.warn('Email credentials not configured, skipping email check');
      resolve({ success: false, message: 'Email not configured', processed: 0 });
      return;
    }

    const imap = new Imap(getImapConfigObject(config));
    let processedCount = 0;

    imap.once('ready', () => {
      console.warn('IMAP connected, checking for new applications...');

      imap.openBox('INBOX', false, (err) => {
        if (err) {
          console.error('Error opening inbox:', err);
          imap.end();
          reject(err);
          return;
        }

        // Search for unread emails
        imap.search(['UNSEEN'], (searchErr, results) => {
          if (searchErr) {
            console.error('Error searching emails:', searchErr);
            imap.end();
            reject(searchErr);
            return;
          }

          if (!results || results.length === 0) {
            console.warn('No new emails found');
            imap.end();
            resolve({ success: true, message: 'No new emails', processed: 0 });
            return;
          }

          console.warn(`Found ${results.length} new email(s)`);

          const fetch = imap.fetch(results, {
            bodies: '',
            markSeen: true
          });

          const emailPromises: Promise<void>[] = [];

          fetch.on('message', (msg) => {
            let buffer = '';

            msg.on('body', (stream) => {
              stream.on('data', (chunk: Buffer) => {
                buffer += chunk.toString('utf8');
              });
            });

            msg.once('end', () => {
              emailPromises.push(
                simpleParser(buffer)
                  .then((parsed) => processEmail(parsed))
                  .then((result) => {
                    if (result) processedCount++;
                  })
                  .catch((parseErr) => console.error('Error parsing email:', parseErr))
              );
            });
          });

          fetch.once('error', (fetchErr) => {
            console.error('Fetch error:', fetchErr);
          });

          fetch.once('end', () => {
            Promise.all(emailPromises)
              .then(() => {
                console.warn(`Processed ${processedCount} application email(s)`);
                imap.end();
                resolve({
                  success: true,
                  message: `Processed ${processedCount} application(s)`,
                  processed: processedCount
                });
              })
              .catch((promiseErr) => {
                imap.end();
                reject(promiseErr);
              });
          });
        });
      });
    });

    imap.once('error', (imapErr) => {
      console.error('IMAP error:', imapErr);
      reject(imapErr);
    });

    imap.once('end', () => {
      console.warn('IMAP connection closed');
    });

    imap.connect();
  });
};

function getImapConfigObject(config: ImapConfig): Imap.Config {
  return {
    user: config.user || '',
    password: config.password || '',
    host: config.host,
    port: config.port,
    tls: config.tls,
    tlsOptions: config.tlsOptions
  };
}

/**
 * Manual trigger for checking emails (called from API)
 */
export const manualCheckEmails = async (): Promise<EmailCheckResult> => {
  try {
    const result = await checkForNewApplications();
    return result;
  } catch (err) {
    const errorMsg = err instanceof Error ? err.message : 'Unknown error';
    console.error('Manual email check failed:', errorMsg);
    return {
      success: false,
      message: errorMsg,
      processed: 0
    };
  }
};

export default { checkForNewApplications, manualCheckEmails };

import { google, calendar_v3 } from 'googleapis';
import { db } from '../db/index.js';
import { googleCalendarTokens } from '../db/schema.js';
import { eq } from 'drizzle-orm';

interface MeetingResult {
  success: boolean;
  meetingLink?: string;
  meetingId?: string;
  error?: string;
}

interface MeetingOptions {
  userId: number;
  title: string;
  startTime: Date;
  duration?: number; // in minutes, default 60
  description?: string;
  attendeeEmail?: string;
  attendeeName?: string;
}

const getOAuth2Client = () => {
  return new google.auth.OAuth2(
    process.env.GOOGLE_CLIENT_ID,
    process.env.GOOGLE_CLIENT_SECRET,
    process.env.GOOGLE_REDIRECT_URI
  );
};

/**
 * Generate a Google Meet link by creating a calendar event with conferencing
 */
export const generateGoogleMeetLink = async (options: MeetingOptions): Promise<MeetingResult> => {
  try {
    // Get user's Google Calendar tokens
    const tokens = await db.query.googleCalendarTokens.findFirst({
      where: eq(googleCalendarTokens.userId, options.userId)
    });

    if (!tokens) {
      return {
        success: false,
        error: 'Google Calendar not connected. Please connect your Google Calendar first.'
      };
    }

    const oauth2Client = getOAuth2Client();
    oauth2Client.setCredentials({
      access_token: tokens.accessToken,
      refresh_token: tokens.refreshToken
    });

    // Handle token refresh if expired
    const tokenExpiry = new Date(tokens.tokenExpiry);
    if (tokenExpiry < new Date()) {
      try {
        const { credentials } = await oauth2Client.refreshAccessToken();
        if (credentials.access_token) {
          await db.update(googleCalendarTokens)
            .set({ 
              accessToken: credentials.access_token, 
              tokenExpiry: new Date(credentials.expiry_date || Date.now() + 3600000).toISOString() 
            })
            .where(eq(googleCalendarTokens.userId, options.userId));
            
          oauth2Client.setCredentials(credentials);
        }
      } catch (refreshError) {
        console.error('Token refresh failed:', refreshError);
        return {
          success: false,
          error: 'Google Calendar token expired. Please reconnect your Google Calendar.'
        };
      }
    }

    const calendar = google.calendar({ version: 'v3', auth: oauth2Client });

    const duration = options.duration || 60;
    const endTime = new Date(options.startTime.getTime() + duration * 60 * 1000);

    const eventRequest: calendar_v3.Schema$Event = {
      summary: options.title,
      description: options.description || '',
      start: {
        dateTime: options.startTime.toISOString(),
        timeZone: 'Asia/Manila'
      },
      end: {
        dateTime: endTime.toISOString(),
        timeZone: 'Asia/Manila'
      },
      conferenceData: {
        createRequest: {
          requestId: `interview-${Date.now()}-${Math.random().toString(36).substring(7)}`,
          conferenceSolutionKey: {
            type: 'hangoutsMeet'
          }
        }
      }
    };

    // Add attendee if provided
    if (options.attendeeEmail) {
      eventRequest.attendees = [{
        email: options.attendeeEmail,
        displayName: options.attendeeName || options.attendeeEmail
      }];
    }

    const response = await calendar.events.insert({
      calendarId: 'primary',
      conferenceDataVersion: 1,
      requestBody: eventRequest
    });

    const meetLink = response.data.hangoutLink;
    const eventId = response.data.id;

    if (!meetLink) {
      return {
        success: false,
        error: 'Failed to generate Google Meet link. Please try again.'
      };
    }

    return {
      success: true,
      meetingLink: meetLink,
      meetingId: eventId || undefined
    };
  } catch (error) {
    console.error('Error generating Google Meet link:', error);
    return {
      success: false,
      error: error instanceof Error ? error.message : 'Failed to generate meeting link'
    };
  }
};

